    64→void Opencore::HandleSignal(int signal, siginfo_t* siginfo, void* ucontext_raw) {
    65→    pthread_mutex_lock(&g_handle_lock);
    66→    Disable();
    67→    Dump(siginfo, ucontext_raw);
